  {"slug":"pulse-comet-elementa","title":"Pulse Comet","description":"Ein Kometen-Spinner zieht einen leuchtenden Schweif um einen sanft pulsierenden Kern und verbindet so Rotation und Puls zu einem auffälligen Ladeeffekt im Dark-Theme.","framework":"css","tags":["loader","comet","pulse","dark","css"],"html":"&lt;div class=\"elx-comet\" role=\"status\" aria-label=\"Laden\"&gt;\n  &lt;span class=\"elx-comet__pulse\"&gt;&lt;/span&gt;\n  &lt;span class=\"elx-comet__trail\"&gt;&lt;/span&gt;\n&lt;/div&gt;","css":".elx-comet{position:relative;width:74px;height:74px;display:grid;place-items:center;background:#0b0b12;margin:auto}\n.elx-comet__pulse{position:absolute;width:16px;height:16px;border-radius:50%;background:radial-gradient(circle at 35% 35%,#10b981,#06b6d4);animation:elx-comet-pulse 1.4s ease-in-out infinite}\n.elx-comet__trail{position:absolute;width:60px;height:60px;border-radius:50%;background:conic-gradient(from 0deg,transparent 0deg,transparent 200deg,#8b5cf6 300deg,#d946ef 360deg);-webkit-mask:radial-gradient(farthest-side,transparent calc(100% - 6px),#000 calc(100% - 5px));mask:radial-gradient(farthest-side,transparent calc(100% - 6px),#000 calc(100% - 5px));animation:elx-comet-spin .9s linear infinite}\n@keyframes elx-comet-spin{to{transform:rotate(360deg)}}\n@keyframes elx-comet-pulse{0%,100%{transform:scale(.8);box-shadow:0 0 6px rgba(16,185,129,.5)}50%{transform:scale(1.15);box-shadow:0 0 16px rgba(16,185,129,.8)}}\n@media (prefers-reduced-motion:reduce){.elx-comet__trail{animation:none;opacity:.8}.elx-comet__pulse{animation:none}}","js":""}
