const GROUPS = [
  ["buttons", BUTTONS, "pass"],
  ["cards", CARDS, "unchecked"],
  ["loaders", LOADERS, "unchecked"],
  ["inputs", INPUTS, "pass"],
  ["toggles", TOGGLES, "pass"],
  ["backgrounds", BACKGROUNDS, "unchecked"],
];

let created = 0, failed = 0;
const now = Date.now();
let idx = 0;

for (const [category, list, a11y] of GROUPS) {
  console.log(`\n-> ${category}: ${list.length}`);
  for (const c of list) {
    idx++;
    const base = {
      title: c.title,
      description: c.description,
      html: unesc(c.html),
      css: unesc(c.css),
      js: unesc(c.js),
      framework: c.framework,
      category,
      tags: c.tags,
      authorId: AUTHOR_ID,
      authorUsername: AUTHOR_NAME,
      likesCount: 0,
      views: 0,
      a11y,
      createdAt: new Date(now - idx * 60000).toISOString(),
    };
    let done = false;
    for (let attempt = 0; attempt < 3 && !done; attempt++) {
      const slug = attempt === 0 ? c.slug : `${c.slug}-${attempt + 1}`;
      try {
        await db.createDocument(DB, COL, ID.unique(), { ...base, slug }, perms);
        console.log("  ok", slug);
        created++; done = true;
      } catch (e) {
        if (e?.code === 409) continue;
        console.error("  fail", c.slug, "->", e.message);
        failed++; done = true;
      }
    }
  }
}

console.log(`\nFertig. Erstellt: ${created}, Fehler: ${failed}`);
